// Character with configured movement
AMyCharacter::AMyCharacter() {
    GetCharacterMovement()->MaxWalkSpeed = 600.f;
    GetCharacterMovement()->JumpZVelocity = 500.f;
    GetCharacterMovement()->AirControl = 0.2f;
    GetCharacterMovement()->GravityScale = 1.0f;
    GetCharacterMovement()->bCanCrouch = true;
    GetCharacterMovement()->bOrientRotationToMovement = true;
    GetCharacterMovement()->RotationRate = FRotator(0.f, 540.f, 0.f);
}

// Sprint
void AMyCharacter::StartSprint() {
    GetCharacterMovement()->MaxWalkSpeed = 1000.f;
}
void AMyCharacter::StopSprint() {
    GetCharacterMovement()->MaxWalkSpeed = 600.f;
}

// Launch (jump pad)
void AJumpPad::OnOverlap(AActor* OtherActor) {
    if (ACharacter* Char = Cast<ACharacter>(OtherActor)) {
        Char->LaunchCharacter(FVector(0, 0, 1500.f), false, true);
    }
}

// Toggle flying
void AMyCharacter::ToggleFly() {
    if (GetCharacterMovement()->MovementMode == MOVE_Flying) {
        GetCharacterMovement()->SetMovementMode(MOVE_Walking);
    } else {
        GetCharacterMovement()->SetMovementMode(MOVE_Flying);
    }
}

// Projectile with homing
AMyProjectile::AMyProjectile() {
    SphereComp = CreateDefaultSubobject<USphereComponent>(TEXT("Sphere"));
    SetRootComponent(SphereComp);

    ProjectileComp = CreateDefaultSubobject<UProjectileMovementComponent>(TEXT("Projectile"));
    ProjectileComp->InitialSpeed = 3000.f;
    ProjectileComp->MaxSpeed = 3000.f;
    ProjectileComp->ProjectileGravityScale = 0.f; // No gravity
    ProjectileComp->bIsHomingProjectile = true;
    ProjectileComp->HomingAccelerationMagnitude = 5000.f;

    SetLifeSpan(5.f);
}

void AMyProjectile::SetHomingTarget(AActor* Target) {
    if (Target) {
        ProjectileComp->HomingTargetComponent = Target->GetRootComponent();
    }
}

// Top-down pawn with floating movement
AMyTopDownPawn::AMyTopDownPawn() {
    FloatingMovement = CreateDefaultSubobject<UFloatingPawnMovement>(TEXT("Movement"));
    FloatingMovement->MaxSpeed = 800.f;
    FloatingMovement->Acceleration = 2000.f;
    FloatingMovement->Deceleration = 2000.f;
}
